1	const NEIGHBOR_OFFSETS: Array<[number, number]> = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1]
5	];
6	
7	// Helper to parse serialized cell coordinates back to tuple
8	const parseCell = (serialized: string): [number, number] => {
9	  return serialized.split(',').map(Number) as [number, number];
10	};
11	
12	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
13	  // Create a set for O(1) cell lookup instead of O(N) array search
14	  const gridSet = new Set(grid.map(([x, y]) => `${x},${y}`));
15	
16	  // Helper to check if a cell exists at coordinates
17	  const cellExists = (x: number, y: number): boolean => {
18	    return gridSet.has(`${x},${y}`);
19	  };
20	
21	  // Count neighbors for each cell
22	  const countNeighbors = (x: number, y: number): number => {
23	    return NEIGHBOR_OFFSETS.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
24	  };
25	
26	  // Rule 1 & 3: Live cells survive with 2-3 neighbors
27	  const survivingCells = grid.filter(([x, y]) => {
28	    const neighbors = countNeighbors(x, y);
29	    return neighbors >= 2 && neighbors <= 3;
30	  });
31	
32	  // Rule 4: Dead cells with exactly 3 neighbors become alive
33	  const deadCellsSet = new Set<string>();
34	  // Find all dead cells adjacent to live cells
35	  for (const [x, y] of grid) {
36	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
37	      const nx = x + dx;
38	      const ny = y + dy;
39	      if (!cellExists(nx, ny)) {
40	        deadCellsSet.add(`${nx},${ny}`);
41	      }
42	    }
43	  }
44	
45	  // Create new cells from dead cells with exactly 3 neighbors
46	  const newCells: Array<[number, number]> = [];
47	  for (const cell of deadCellsSet) {
48	    const [x, y] = parseCell(cell);
49	    if (countNeighbors(x, y) === 3) {
50	      newCells.push([x, y]);
51	    }
52	  }
53	
54	  // Combine surviving cells and new cells
55	  const result = [...survivingCells, ...newCells];
56	  return result;
57	}
